                      <td>{p.current_sales}</td>
                      <td>
                        <span className={`badge ${p.stock <= p.reorder_level ? 'red' : 'green'}`}>
                          {p.stock <= p.reorder_level ? 'Low Stock' : 'OK'}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}

          </div>
        </div>
      </div>
    </div>
  );
}
